        stats.protocols.v3.fetched++;
        stats.fetched++;
        const tokens = getPoolTokens(pool);
        if (tokens.length === 0) continue;
        const normalized = normalizePoolState(addr, pool.protocol, tokens, raw, pool.metadata);
        if (normalized) {
          stateCache.set(addr, normalized);
